import { Item } from '@/models/menu';
import { loadConfig } from '@/services/config.service';
import { url } from './api.service';

export const getMenuItems = async (): Promise<Item[]> => {
    const cacheKey = '_menuItems';
    const cached = window.cache.get(cacheKey);
    if (cached) {
        console.log('getMenuItems@cache', cached);
        return cached as Item[];
    }
    console.log('getMenuItems@fetch');

    const r = await fetch(url('/isiWeb/web/v1/menu'), {
        credentials: 'include',
    });

    if (!r.ok) {
        throw new Error(`Menu response status not OK: ${r.status}`);
    }

    const response = await r.json();
    let menu: Item[] = response.data as Item[];

    if (menu.length === 0) {
        menu = loadConfig().aside.defaultMenu;
    }

    window.cache.set(cacheKey, menu);
    console.log('getMenuItems@cache set', menu);

    return menu;
};
